ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/journalism#>
PREFIX p: <http://ambrosia.example.org/journalism/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE vague {
  full: { SELECT ?age_group ?income_level WHERE {
  ?audience a :Audience .
  ?articles a :Articles .
  ?audience p:hasArticles ?articles .
  ?audience p:Age_Group ?age_group .
  ?audience p:Income_Level ?income_level .
  ?articles p:PublicationDate ?publicationdate_o .
}
ORDER BY DESC(?publicationdate_o)
LIMIT 1 }
  component: { SELECT ?income_level WHERE {
  ?audience a :Audience .
  ?articles a :Articles .
  ?audience p:hasArticles ?articles .
  ?audience p:Income_Level ?income_level .
  ?articles p:PublicationDate ?publicationdate_o .
}
ORDER BY DESC(?publicationdate_o)
LIMIT 1 }
  component_2: { SELECT ?age_group WHERE {
  ?audience a :Audience .
  ?articles a :Articles .
  ?audience p:hasArticles ?articles .
  ?audience p:Age_Group ?age_group .
  ?articles p:PublicationDate ?publicationdate_o .
}
ORDER BY DESC(?publicationdate_o)
LIMIT 1 }
}
